**Idea — row-by-row DFS with conflict sets**: For each row, try each column. Track used columns, used `r-c` diagonals, used `r+c` anti-diagonals. On row === n, build board strings.

```javascript
function solveNQueens(n) {
  const out = [];
  const cols = new Set(), d1 = new Set(), d2 = new Set();
  const queens = new Array(n).fill(-1);
  function dfs(r) {
    if (r === n) {
      const board = [];
      for (let i = 0; i < n; i++) {
        const row = new Array(n).fill('.');
        row[queens[i]] = 'Q';
        board.push(row.join(''));
      }
      out.push(board);
      return;
    }
    for (let c = 0; c < n; c++) {
      if (cols.has(c) || d1.has(r - c) || d2.has(r + c)) continue;
      cols.add(c); d1.add(r - c); d2.add(r + c); queens[r] = c;
      dfs(r + 1);
      cols.delete(c); d1.delete(r - c); d2.delete(r + c);
    }
  }
  dfs(0);
  return out.sort((a, b) => JSON.stringify(a).localeCompare(JSON.stringify(b)));
}
