**Idea — DFS with row/col/box constraint sets**: Pre-fill three boolean arrays `rows[9][10]`, `cols[9][10]`, `boxes[9][10]`. Walk cells; on empty, try digits 1..9 not yet used in row/col/box, recurse, undo on backtrack.

```javascript
function solveSudoku(board) {
  const rows = Array.from({ length: 9 }, () => new Array(10).fill(false));
  const cols = Array.from({ length: 9 }, () => new Array(10).fill(false));
  const boxes = Array.from({ length: 9 }, () => new Array(10).fill(false));
  for (let r = 0; r < 9; r++) for (let c = 0; c < 9; c++) {
    if (board[r][c] !== '.') {
      const d = +board[r][c];
      rows[r][d] = cols[c][d] = boxes[3 * ((r / 3) | 0) + ((c / 3) | 0)][d] = true;
    }
  }
  function dfs(r, c) {
    if (r === 9) return true;
    if (c === 9) return dfs(r + 1, 0);
    if (board[r][c] !== '.') return dfs(r, c + 1);
    const b = 3 * ((r / 3) | 0) + ((c / 3) | 0);
    for (let d = 1; d <= 9; d++) {
      if (rows[r][d] || cols[c][d] || boxes[b][d]) continue;
      board[r][c] = String(d);
      rows[r][d] = cols[c][d] = boxes[b][d] = true;
      if (dfs(r, c + 1)) return true;
      board[r][c] = '.';
      rows[r][d] = cols[c][d] = boxes[b][d] = false;
    }
    return false;
  }
  dfs(0, 0);
  return board;
}
```

**Time**: exponential worst, fast in practice. **Space**: O(1) extra.

