**Idea — per-word DFS**: For each word in the list, try standard word-search backtracking from every cell. Collect found words; final sort.

```javascript
function findRouteWords(board, words) {
  const m = board.length, n = board[0].length;
  function exists(word) {
    function dfs(r, c, k) {
      if (k === word.length) return true;
      if (r < 0 || c < 0 || r >= m || c >= n || board[r][c] !== word[k]) return false;
      const tmp = board[r][c];
      board[r][c] = '#';
      const found = dfs(r + 1, c, k + 1) || dfs(r - 1, c, k + 1) || dfs(r, c + 1, k + 1) || dfs(r, c - 1, k + 1);
      board[r][c] = tmp;
      return found;
    }
    for (let r = 0; r < m; r++) for (let c = 0; c < n; c++) if (dfs(r, c, 0)) return true;
    return false;
  }
  const out = [];
  for (const w of words) if (exists(w)) out.push(w);
  return out.sort((a, b) => JSON.stringify(a).localeCompare(JSON.stringify(b)));
}
```

**Time**: O(W * m*n*4^L). **Space**: O(L). A Trie speeds this up further on large word lists.

