**Idea — DFS over operand boundaries with mul fix**: Walk the string, at each position try each prefix as the next operand. Track running `value` and `prev` (last contribution) — when applying `*`, undo `prev` and apply `prev * cur`.

```javascript
function addOperators(num, target) {
  const out = [];
  function dfs(i, expr, value, prev) {
    if (i === num.length) { if (value === target) out.push(expr); return; }
    for (let j = i + 1; j <= num.length; j++) {
      const seg = num.slice(i, j);
      if (seg.length > 1 && seg[0] === '0') break;
      const cur = parseInt(seg, 10);
      if (i === 0) {
        dfs(j, seg, cur, cur);
      } else {
        dfs(j, expr + '+' + seg, value + cur, cur);
        dfs(j, expr + '-' + seg, value - cur, -cur);
        dfs(j, expr + '*' + seg, value - prev + prev * cur, prev * cur);
      }
    }
  }
  dfs(0, '', 0, 0);
  return out.sort((a, b) => JSON.stringify(a).localeCompare(JSON.stringify(b)));
}
```

**Time**: O(n * 4^n). **Space**: O(n).
